const express = require('express');
const router = express.Router();

router.get('/profile', (req, res) => {
  const { id } = req.params;
  const { name, email } = req.user;

  const userProfile = {
    id,
    name,
    email,
  };

  res.json(userProfile);
});

module.exports = router;